  const cycleStates = ['idle', 'thinking', 'executing', 'idle', 'thinking', 'idle', 'executing'];
  let cycleIdx = 0;
  let lastCycleSwitch = Date.now();
  const CYCLE_INTERVAL = 4000; // 4 seconds per state

  setInterval(() => {
    if (!state.snapshot) return;

    // Auto-cycle through states for animation demo
    // Real agent state from server overrides when available
    const serverState = state.snapshot.agent?.state;
    const now = Date.now();
    if (now - lastCycleSwitch > CYCLE_INTERVAL) {
      cycleIdx = (cycleIdx + 1) % cycleStates.length;
      lastCycleSwitch = now;
    }

    // Use server state if it's not 'idle', otherwise use local cycle
    const activeState = (serverState && serverState !== 'idle') ? serverState : cycleStates[cycleIdx];
    const normalized = normalizeAgentState(activeState, activeState);

    drawSidebarSprite(normalized, state.spriteTick);
    state.spriteTick++;
  }, 520);
