      drawSidebarSprite(normalized, a.frame || 0);
    };
    img.onerror = () => {
      state._sidebarAvatarImg = null;
      state._sidebarAvatarReady = false;
    };
    img.src = cacheBustedUrl;
  }
  drawSidebarSprite(normalized, a.frame || 0);
